const baseUrl = $('Edit Fields').first().json.your_site.replace(/\/$/, '');
const links = $json.all_links || [];

const importantKeywords = [
  "about",
  "service",
  "solution",
  "product",
  "blog",
  "case",
  "portfolio",
  "contact",
  "career"
];

const pages = [];

for (let link of links) {

  if (!link) continue;

  let fullUrl = "";

  // convert relative links to full URL
  if (link.startsWith("/")) {
    fullUrl = baseUrl + link;
  } 
  else if (link.startsWith(baseUrl)) {
    fullUrl = link;
  }

  if (!fullUrl) continue;

  // remove anchors and query params
  fullUrl = fullUrl.split("#")[0].split("?")[0];

  // check if link contains important keywords
  const lowerUrl = fullUrl.toLowerCase();

  const isImportant = importantKeywords.some(keyword =>
    lowerUrl.includes(keyword)
  );

  if (isImportant) {
    pages.push(fullUrl);
  }
}

// always include homepage
pages.unshift(baseUrl);

// remove duplicates
const uniquePages = [...new Set(pages)];

return uniquePages.map(url => {
  return {
    json: {
      page_url: url
    }
  };
});

const item = $json;

// paragraphs
let paragraphs = item.content || [];
let wordCount = 0;

if (Array.isArray(paragraphs)) {
  wordCount = paragraphs.join(" ").split(/\s+/).length;
}

// H2 cleanup
let h2 = [];
if (Array.isArray(item.h2)) {
  h2 = [...new Set(item.h2.map(h => h.trim()))];
}

// counts
const internalLinks = item.internal_links ? item.internal_links.length : 0;
const externalLinks = item.external_links ? item.external_links.length : 0;
const images = item.images ? item.images.length : 0;

return [{
  json: {
    Website:$('Edit Fields').first().json.competitor_site ,
    Page_URL:$('Edit Fields').first().json.competitor_site ,
    Page_Title: item.title || "",
    Meta_Description: item.meta_description || "",
    H1: item.h1 || "",
    H2: h2.join(", "),
    Word_Count: wordCount,
    Internal_Links: internalLinks,
    External_Links: externalLinks,
    Images: images,
    Collected_Date: new Date().toISOString().split('T')[0]
  }
}];

