const yourData = [];
const competitorData = [];

for (const item of $input.all()) {

  if (item.json.Website !== undefined) {
    yourData.push(item.json);
  }

  if (item.json.Competitor_Website !== undefined) {
    competitorData.push(item.json);
  }

}

const mergedData = {
  your_website_data: yourData,
  competitor_website_data: competitorData
};

return [
  {
    json: mergedData,
    pairedItem: { item: 0 }
  }
];

// Get Gemini response text
let rawText = $json.content.parts[0].text;

// Remove markdown code blocks
rawText = rawText.replace(/```json/g, '')
                 .replace(/```/g, '')
                 .trim();

// Remove markdown bold (**text**)
rawText = rawText.replace(/\*\*/g, '');

// Extract JSON object
const jsonMatch = rawText.match(/\{[\s\S]*\}/);

if (!jsonMatch) {
  throw new Error("No valid JSON found in AI output: " + rawText);
}

let parsed;

try {
  parsed = JSON.parse(jsonMatch[0]);
} catch (error) {
  throw new Error("AI output is not valid JSON: " + jsonMatch[0]);
}

// Return parsed JSON
return [
  {
    json: parsed
  }
];
